  "decomposed_queries": [
    {
      "question": "What Phase 3 non-small cell lung cancer trials exist?",
      "sql": "SELECT \"NCT\", \"Author\", \"Year\", \"Originial publication or Follow-up\", \"Trial phase\", \"Control arm\", \"Cancer type\", \"Name of ICI\", \"Treatment regimen\" FROM clinical_trials WHERE \"Cancer type\" = 'Non-Small Cell Lung' AND \"Trial phase\" = 'Phase 3';"
    },
    {
      "question": "Among Phase 3 NSCLC trials, which ones include immunotherapy in the treatment regimen?",
      "sql": "SELECT \"NCT\", \"Author\", \"Year\", \"Originial publication or Follow-up\", \"Trial phase\", \"Control arm\", \"Cancer type\", \"Name of ICI\", \"Treatment regimen\" FROM clinical_trials WHERE \"Cancer type\" = 'Non-Small Cell Lung' AND \"Trial phase\" = 'Phase 3' AND \"Name of ICI\" IS NOT NULL;"
    },
    {
      "question": "Among Phase 3 NSCLC trials, which have a control arm containing an mTOR inhibitor?",
      "sql": "SELECT \"NCT\", \"Author\", \"Year\", \"Originial publication or Follow-up\", \"Trial phase\", \"Control arm\", \"Cancer type\", \"Name of ICI\", \"Treatment regimen\" FROM clinical_trials WHERE \"Cancer type\" = 'Non-Small Cell Lung' AND \"Trial phase\" = 'Phase 3' AND \"Control arm\" LIKE '%mTOR%';"
    },
    {
      "question": "Among Phase 3 NSCLC trials, which do not use chemotherapy in the control arm?",
      "sql": "SELECT \"NCT\", \"Author\", \"Year\", \"Originial publication or Follow-up\", \"Trial phase\", \"Control arm\", \"Cancer type\", \"Name of ICI\", \"Treatment regimen\" FROM clinical_trials WHERE \"Cancer type\" = 'Non-Small Cell Lung' AND \"Trial phase\" = 'Phase 3' AND \"Control arm\" NOT LIKE '%Chemotherapy%';"
    }
  ]
}
